1	export type QuoteStep = {
2	  op: "quote";
3	  items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>;
4	};
5	
6	export type Step = QuoteStep;
7	
8	export type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: Step[];
11	};
12	
13	export type QuoteResult = { premium: number };
14	export type StepResult = QuoteResult;
15	
16	export type ScenarioResult = {
17	  results: StepResult[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	const BASE_PREMIUM: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	};
27	
28	const quote = (step: QuoteStep): QuoteResult => {
29	  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
30	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
31	  return { premium: itemsBase + firstInsurance + PROCESSING_FEE };
32	};
33	
34	export const runScenario = (scenario: Scenario): ScenarioResult => {
35	  const results = scenario.steps.map(quote);
36	  return { results };
37	};
